import Footer from "@/components/Footer";
import { LangAndTheme } from "@/components/RightContent";
import { appTitle, fallbackEnUs, t } from "@/global";
import { LoginForm } from "@ant-design/pro-form";
import { Alert, Button, Form, message, theme } from "antd";
const { useToken } = theme;
import styles from './../Login/index.less';
import { useIntl, history, useLocation } from "@umijs/max";
import { userTfaVerifyByName } from "@/services/api";
import { useState } from "react";
import queryString from "query-string";
import { TfaCodeComponent } from "@/pages/account/Settings/components/tfa/tfa";
import { makeQRCodeSection, makeSubDescriptionStep2, makeTfaSetupComponents } from "@/pages/account/Settings/components/tfa/TfaSetupComponents";
import tfaStyles from '@/pages/account/Settings/components/tfa/tfa.less';
import { handleDownloadCodes, makeBackupCodesComponents } from "@/pages/account/Settings/components/tfa/BackupCodes";

const ResetPassword: React.FC = () => {
  const { token } = useToken();
  const intl = useIntl();
  const [form] = Form.useForm();
  const [setupCompleted, setSetupCompleted] = useState<boolean>(false);
  const [backupCodes, setBackupCodes] = useState<string[]>([]);
  const [err, setErr] = useState<string | undefined>(undefined);
  const location = useLocation();
  const query = queryString.parse(location.search);
  const { secret, username, totp_url } = query as { secret: string | undefined, username: string | undefined, totp_url: string | undefined };

  const plain = (text: string, defaultMessage = '') => t(`pages.account.tfa.${text}`, true, defaultMessage || text, intl) as string;

  const handleTfaVerify = async (values: any) => {
    try {
      const resp = await userTfaVerifyByName(values);
      if (resp.success) {
        message.success('2FA enabled successfully! Please log in again.');
        setBackupCodes(resp.backup_codes ?? []);
        setSetupCompleted(true);
        return true;
      } else {
        setErr('Can\'t verify the code. Check that code and local time settings are correct!');
        return false;
      }
    } catch (error: any) {
      message.error(typeof error === 'string' ? error : error?.message || 'Verify failed');
      return false;
    }
  };

  const makeCodeComponent = () => (
    <div>
      <TfaCodeComponent
        form={form}
        width={180}
        isBackupCodeAcceptable={false}
        autoFocus={true}
        err={err}
        setErr={setErr}
        onChange={(v: string) => {
          if (v.length === 6) {
            handleTfaVerify({ tfa_code: v, name: username, secret: secret });
          }
        }}
      />
    </div>
  );

  const makeTfaSetupDescription = () => {
    let description = t('enforce_2fa_alert', true);
    if (username) {
      description = `Hi ${username}, ` + description;
    }
    return <Alert
      description={description}
      type="info"
    />
  };

  const makeComponentStep2 = () => (
    <div className={tfaStyles.step2}>
      <div>
        {makeSubDescriptionStep2()}
        <div style={{ height: '15px' }} />
        {makeCodeComponent()}
      </div>
      <div>
        {makeQRCodeSection(totp_url || '', 120)}
      </div>
    </div>
  );

  const getSetupNotCompleted = () => {
    return (
      <div className={tfaStyles.modal}>
        {makeTfaSetupDescription()}
        {makeTfaSetupComponents()}
        {makeComponentStep2()}
      </div>
    );
  }

  const getSetupCompleted = () => {
    return (<>
      <div style={{ marginBottom: 24 }}>
        <Alert
          message={t('setup_2fa_success_alert')}
          type="success"
          showIcon
        />
      </div>
      <div>
        {makeBackupCodesComponents(plain, backupCodes)}
      </div>
      <div style={{ display: 'flex', justifyContent: 'center', marginTop: '16px' }}>
        <Button
          type="primary"
          onClick={() => {
            handleDownloadCodes(backupCodes);
          }}
        >
          {plain('Download codes')}
        </Button>
      </div>
    </>
    )
  }




  return fallbackEnUs(
    <div className={styles.container} style={{ backgroundColor: token.colorBgContainer }}>
      <LangAndTheme />
      <div className={styles.content}>
        <LoginForm
          form={form}
          logo={<img alt="logo" src="./logo.svg" />}
          title="RustDesk"
          subTitle={t('app.title', true, appTitle as string)}
          onFinish={async (values) => {

          }}
          submitter={{
            render: () => {
              return (
                <>
                  {(
                    <Button
                      style={{ marginTop: '20px' }}
                      size="large"
                      block
                      onClick={() => {
                        history.push('/user/login');
                      }}
                    >
                      {t('Back')}
                    </Button>
                  )}
                </>
              );
            },
            submitButtonProps: {
              size: 'large',
              style: {
                width: '100%',
              },
            },
          }}
        >
          {setupCompleted ? getSetupCompleted() : getSetupNotCompleted()}
        </LoginForm>
        <Footer />
      </div >
    </div>
  );
};

export default ResetPassword;
